 158→const decorateNotificationMedia = (notification) => {
 159→    if(!notification || typeof notification !== 'object'){
 160→        return notification;
 161→    }
 162→
 163→    const senderAvatarMedia = createMediaResponsePayload('avatars', notification.users?.image_url, 'card');
 164→    const journalThumbnailMedia = createMediaResponsePayload('journal-images', notification.journals?.thumbnail_url, 'card');
 165→    const journalUserAvatarMedia = createMediaResponsePayload('avatars', notification.journals?.users?.image_url, 'card');
 166→
 167→    return {
 168→        ...notification,
 169→        users: notification.users ? {
 170→            ...notification.users,
 171→            image_url: senderAvatarMedia?.preferred_url || notification.users.image_url || null,
 172→            avatar_media: senderAvatarMedia
 173→        } : notification.users,
 174→        journals: notification.journals ? {
 175→            ...notification.journals,
 176→            thumbnail_url: journalThumbnailMedia?.preferred_url || notification.journals.thumbnail_url || null,
 177→            thumbnail_media: journalThumbnailMedia,
 178→            users: notification.journals.users ? {
 179→                ...notification.journals.users,
 180→                image_url: journalUserAvatarMedia?.preferred_url || notification.journals.users.image_url || null,
 181→                avatar_media: journalUserAvatarMedia
 182→            } : notification.journals.users
 183→        } : notification.journals
 184→    };
 185→};
