 187→const parseLimitWithinRange = (value, min, max, fallback = null) => {
 188→    const parsed = Number.parseInt(value, 10);
 189→    if (Number.isNaN(parsed)) {
 190→        return fallback;
 191→    }
 192→    if (parsed < min || parsed > max) {
 193→        return null;
 194→    }
 195→    return parsed;
 196→};
