 324→router.get('/getFollowsData', async(req, res) => {
 325→    const {userId, loggedInUserId} = req.query;
 326→    if(!userId && !loggedInUserId) return res.status(400).json({error: 'userId or loggendUserId is undefined '});
 327→    // console.log(req.query)
 328→    try {
 329→        const followersCountPromise = supabase
 330→        .from('follows')
 331→        .select('id', {count: 'exact', head: true})
 332→        .eq('following_id', userId);
 333→
 334→        const followingCountPromise = supabase
 335→        .from('follows')
 336→        .select('id', {count: 'exact', head: true})
 337→        .eq('follower_id', userId)
 338→
 339→        const isFollowingPromise = supabase
 340→        .from('follows')
 341→        .select('id', {count: 'exact', head: true})
 342→        .eq('follower_id', loggedInUserId)
 343→        .eq('following_id', userId)
 344→
 345→        const [followersCountResult, followingsCountResult, isFollowingResult] = await Promise.all([
 346→            followersCountPromise, followingCountPromise, isFollowingPromise,
 347→        ])
 348→
 349→
 350→        const {count: followersCount, error: errorFollowers } = followersCountResult;
 351→        const {count: followingsCount, error: errorFollowings} = followingsCountResult;
 352→        const {count: isFollowingCount, error: errorIsfollowing} = isFollowingResult;
 353→
 354→        if(errorFollowers || errorFollowings || errorIsfollowing){
 355→            console.error('supabase error while fetching data:', errorFollowers.message, errorFollowings.message, errorIsfollowing.message)
 356→            return res.status(500).json({error: 'failed to fetch data'})
 357→        }
 358→
 359→        return res.status(200).json({
 360→            followersCount: followersCount,
 361→            followingsCount: followingsCount,
 362→            isFollowing: isFollowingCount > 0
 363→        })
 364→
 365→    } catch (error) {
 366→        console.error('Error in Promise.all:', error);
 367→        res.status(500).json({ error: 'An unexpected error occurred' });
 368→    }
 369→
 370→})
