  1→const STORAGE_PUBLIC_SEGMENT = '/storage/v1/object/public/';
  2→const VARIANT_SUFFIXES = {
  3→    thumbnail: '__thumb',
  4→    card: '__card',
  5→    detail: '__detail',
  6→    original: '__original'
  7→};
  8→
  9→export const MEDIA_VARIANT_CONFIG = {
