 35→
 36→const escapeRegExp = (value = '') => value.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
 37→
 38→const getBaseNameData = (fileName = '') => {
 39→    const match = fileName.match(/^(.*?)(__(?:thumb|card|detail|original))?(\.[^.]*)$/i);
 40→    if(!match){
 41→        return {
 42→            baseName: fileName,
 43→            extension: '',
 44→            variantKey: null
 45→        };
 46→    }
 47→
 48→    const variantEntry = Object.entries(VARIANT_SUFFIXES)
 49→        .find(([, suffix]) => suffix.toLowerCase() === (match[2] || '').toLowerCase());
 50→
 51→    return {
 52→        baseName: match[1],
 53→        extension: match[3] || '',
 54→        variantKey: variantEntry?.[0] || null
 55→    };
 56→};
 57→
 58→const getBucketPathFromUrl = (bucket, url = '') => {
 59→    if(typeof url !== 'string' || !url){
 60→        return '';
 61→    }
 62→
 63→    try {
 64→        const parsed = new URL(url);
 65→        const publicPrefix = `${STORAGE_PUBLIC_SEGMENT}${bucket}/`;
 66→        const index = parsed.pathname.indexOf(publicPrefix);
 67→        if(index === -1){
 68→            return '';
 69→        }
 70→        return decodeURIComponent(parsed.pathname.slice(index + publicPrefix.length));
 71→    } catch {
 72→        return '';
 73→    }
 74→};
 75→
 76→const createPublicUrlForPath = (bucket, url = '', path = '') => {
 77→    if(!path){
 78→        return typeof url === 'string' ? url : null;
 79→    }
 80→
 81→    if(typeof url === 'string' && url){
 82→        try {
 83→            const parsed = new URL(url);
 84→            const publicPrefix = `${STORAGE_PUBLIC_SEGMENT}${bucket}/`;
 85→            const index = parsed.pathname.indexOf(publicPrefix);
 86→            if(index !== -1){
 87→                parsed.pathname = `${parsed.pathname.slice(0, index + publicPrefix.length)}${path}`;
 88→                parsed.search = '';
 89→                parsed.hash = '';
 90→                return parsed.toString();
 91→            }
 92→        } catch {
 93→            return url;
 94→        }
 95→    }
 96→
 97→    return null;
 98→};
 99→
100→export const getVariantPathSet = (path = '') => {
101→    if(typeof path !== 'string' || !path){
102→        return {
103→            representativePath: '',
104→            thumbnailPath: '',
105→            cardPath: '',
106→            detailPath: '',
107→            originalPath: '',
108→            isVariantManaged: false
109→        };
110→    }
111→
112→    const slashIndex = path.lastIndexOf('/');
113→    const directory = slashIndex === -1 ? '' : path.slice(0, slashIndex + 1);
114→    const fileName = slashIndex === -1 ? path : path.slice(slashIndex + 1);
115→    const { baseName, extension, variantKey } = getBaseNameData(fileName);
116→
117→    if(!variantKey){
118→        return {
119→            representativePath: path,
120→            thumbnailPath: path,
121→            cardPath: path,
122→            detailPath: path,
123→            originalPath: path,
124→            isVariantManaged: false
125→        };
126→    }
127→
128→    return {
129→        representativePath: `${directory}${baseName}${VARIANT_SUFFIXES.detail}${extension}`,
130→        thumbnailPath: `${directory}${baseName}${VARIANT_SUFFIXES.thumbnail}${extension}`,
131→        cardPath: `${directory}${baseName}${VARIANT_SUFFIXES.card}${extension}`,
132→        detailPath: `${directory}${baseName}${VARIANT_SUFFIXES.detail}${extension}`,
133→        originalPath: `${directory}${baseName}${VARIANT_SUFFIXES.original}${extension}`,
134→        isVariantManaged: true
135→    };
136→};
137→
138→export const buildVariantDescriptor = (bucket, urlOrPath = '') => {
139→    const input = typeof urlOrPath === 'string' ? urlOrPath : '';
140→    const path = input.includes('http') ? getBucketPathFromUrl(bucket, input) : input;
141→    if(!path){
142→        return null;
143→    }
144→
145→    const pathSet = getVariantPathSet(path);
146→    const thumbnailUrl = createPublicUrlForPath(bucket, input, pathSet.thumbnailPath);
147→    const cardUrl = createPublicUrlForPath(bucket, input, pathSet.cardPath);
148→    const detailUrl = createPublicUrlForPath(bucket, input, pathSet.detailPath);
149→    const originalUrl = createPublicUrlForPath(bucket, input, pathSet.originalPath);
150→
151→    return {
152→        bucket,
153→        path: pathSet.representativePath,
154→        thumbnailPath: pathSet.thumbnailPath,
155→        cardPath: pathSet.cardPath,
156→        detailPath: pathSet.detailPath,
157→        originalPath: pathSet.originalPath,
158→        isVariantManaged: pathSet.isVariantManaged,
159→        thumbnailUrl: thumbnailUrl || input,
160→        cardUrl: cardUrl || input,
161→        detailUrl: detailUrl || input,
162→        originalUrl: originalUrl || input
163→    };
164→};
165→
166→export const pickVariantUrl = (bucket, urlOrPath, usage = 'card') => {
167→    const descriptor = buildVariantDescriptor(bucket, urlOrPath);
168→    if(!descriptor){
169→        return typeof urlOrPath === 'string' ? urlOrPath : null;
170→    }
171→
172→    if(usage === 'thumbnail'){
173→        return descriptor.thumbnailUrl;
174→    }
175→    if(usage === 'detail'){
176→        return descriptor.detailUrl;
177→    }
178→    if(usage === 'original'){
179→        return descriptor.originalUrl;
180→    }
181→    return descriptor.cardUrl;
182→};
183→
184→export const listVariantPathsForDeletion = (path = '') => {
185→    const descriptor = getVariantPathSet(path);
186→    if(!descriptor.representativePath){
187→        return [];
188→    }
189→
190→    const paths = descriptor.isVariantManaged
191→        ? [
192→            descriptor.thumbnailPath,
193→            descriptor.cardPath,
194→            descriptor.detailPath,
195→            descriptor.originalPath
196→        ]
197→        : [descriptor.representativePath];
198→
199→    return [...new Set(paths.filter(Boolean))];
200→};
201→
202→export const isRepresentativeVariantPath = (path = '') => {
203→    const descriptor = getVariantPathSet(path);
204→    return descriptor.representativePath === path;
205→};
206→
207→export const isPrimaryListableFileName = (fileName = '') => {
208→    const { variantKey } = getBaseNameData(fileName);
209→    return !variantKey || variantKey === 'detail';
210→};
211→
212→export const createVariantFileNames = (baseFileName = '') => {
213→    const { baseName, extension } = getBaseNameData(baseFileName);
214→    return {
215→        thumbnail: `${baseName}${VARIANT_SUFFIXES.thumbnail}${extension || '.webp'}`,
216→        card: `${baseName}${VARIANT_SUFFIXES.card}${extension || '.webp'}`,
217→        detail: `${baseName}${VARIANT_SUFFIXES.detail}${extension || '.webp'}`,
218→        original: `${baseName}${VARIANT_SUFFIXES.original}${extension || '.webp'}`
219→    };
220→};
221→
222→export const createMediaResponsePayload = (bucket, urlOrPath = '', usage = 'card') => {
223→    const descriptor = buildVariantDescriptor(bucket, urlOrPath);
224→    if(!descriptor){
225→        return null;
226→    }
227→
228→    return {
229→        bucket,
230→        path: descriptor.path,
231→        thumbnail_url: descriptor.thumbnailUrl,
232→        card_url: descriptor.cardUrl,
233→        detail_url: descriptor.detailUrl,
234→        original_url: descriptor.originalUrl,
235→        preferred_url: pickVariantUrl(bucket, urlOrPath, usage)
236→    };
237→};
238→
239→export const buildPathMatcher = (path = '') => {
240→    const candidates = listVariantPathsForDeletion(path).map((item) => escapeRegExp(item));
241→    if(candidates.length === 0){
242→        return null;
243→    }
244→    return new RegExp(`/(?:${candidates.join('|')})$`, 'i');
245→};
