  19→// ── Cluster mode: fork one worker per CPU core ──
  20→// Set CLUSTER_ENABLED=true in production to use all CPU cores.
  21→// Disabled by default so local dev / single-core hosts work without surprises.
  22→const CLUSTER_ENABLED = process.env.CLUSTER_ENABLED === 'true';
  23→const WORKER_COUNT = parseInt(process.env.WORKER_COUNT, 10) || os.cpus().length;
  24→
  25→if (CLUSTER_ENABLED && cluster.isPrimary) {
  26→    console.log(`Primary ${process.pid} starting ${WORKER_COUNT} workers...`);
  27→    for (let i = 0; i < WORKER_COUNT; i++) {
  28→        cluster.fork();
  29→    }
  30→    cluster.on('exit', (worker, code, signal) => {
  31→        console.warn(`Worker ${worker.process.pid} exited (code=${code}, signal=${signal}). Restarting...`);
  32→        cluster.fork();
  33→    });
  34→    // Primary does nothing else — workers handle all requests
  35→} else {
