 255→const extractFromLexical = (contentJson) => {
 256→    try {
 257→        const parsed = typeof contentJson === 'string' ? JSON.parse(contentJson) : contentJson;
 258→        const texts = [];
 259→        let firstImage = null;
 260→
 261→        const walk = (node) => {
 262→            if (!node || typeof node !== 'object') return;
 263→
 264→            const nodeType = String(node.type || node.__type || '').trim().toLowerCase();
 265→            if (nodeType === 'text' && typeof node.text === 'string') {
 266→                texts.push(node.text);
 267→            }
 268→
 269→            const isImageNode = nodeType === 'image' || nodeType.endsWith('image') || nodeType.includes('image');
 270→            if (!firstImage && isImageNode) {
 271→                const image = imageFromNodeLike(node);
 272→                if (image) {
 273→                    firstImage = image;
 274→                }
 275→            }
 276→
 277→            if (Array.isArray(node.children)) {
 278→                node.children.forEach(walk);
 279→            }
 280→        };
 281→
 282→        if (parsed?.root) {
 283→            walk(parsed.root);
 284→        }
 285→
 286→        return {
 287→            text: normalizeWhitespace(texts.join(' ')),
 288→            image: firstImage
 289→        };
