 348→const isPrivateIpv4Address = (ip) => {
 349→    const parts = ip.split('.').map((part) => Number(part));
 350→    if (parts.length !== 4 || parts.some((part) => !Number.isInteger(part) || part < 0 || part > 255)) {
 351→        return true;
 352→    }
 353→
 354→    const [a, b] = parts;
 355→    if (a === 10 || a === 127 || a === 0) return true;
 356→    if (a === 169 && b === 254) return true;
 357→    if (a === 172 && b >= 16 && b <= 31) return true;
 358→    if (a === 192 && b === 168) return true;
 359→    return false;
 360→};
