1025→const buildMetricsPayload = () => {
1026→    const routeStats = Array.from(metricsState.routeStats.entries())
1027→        .map(([route, stat]) => ({
1028→            route,
1029→            count: stat.count,
1030→            avgDurationMs: stat.count > 0 ? Number((stat.totalDurationMs / stat.count).toFixed(2)) : 0,
1031→            maxDurationMs: Number(stat.maxDurationMs.toFixed(2)),
1032→            bytesSent: stat.bytesSent,
1033→            statusBuckets: stat.statusBuckets,
1034→        }))
1035→        .sort((a, b) => b.count - a.count);
1036→
1037→    return {
1038→        startedAt: metricsState.startedAt,
1039→        requests: metricsState.requests,
1040→        responses: metricsState.responses,
1041→        inFlight: metricsState.inFlight,
1042→        bytesSent: metricsState.bytesSent,
1043→        statusBuckets: metricsState.statusBuckets,
1044→        routeStats: routeStats,
1045→    };
1046→};
